import java.io.IOException;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class UserInputHandler {

    public void displayMessage(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("message");
        String sanitizedInput = sanitizeUserInput(userInput);

        String htmlResponse = "<html><body><h1>User Message: " + sanitizedInput + "</h1></body></html>";

        response.getWriter().write(htmlResponse);
    }

    private String sanitizeUserInput(String userInput) {
        // Implement proper input sanitization here
        // For Java, you can use libraries like OWASP Java HTML Sanitizer or ESAPI for input validation and output encoding
        // Below is a simple example of escaping HTML special characters
        return userInput == null ? "" : userInput.replaceAll("<", "&lt;").replaceAll(">", "&gt;");
    }
}

